/* ============================================================
   WEPOSE Profile Assessment — shared report render engine.
   Dipakai oleh index.html (live preview) DAN print.html (yang
   di-render Puppeteer jadi PDF). Karena keduanya memanggil fungsi
   yang SAMA PERSIS, hasil PDF dijamin identik dengan preview.
   ============================================================ */
(function (global) {
  const IDN_MONTHS = ['Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];
  const ROMAN = ['I','II','III','IV'];
  const DIM_NAMES = ['Dokumen Pekerjaan','Stabilitas Finansial','History Perjalanan','Hubungan / Ties'];

  const ASSET_LOGO = "data:image/png;base64,";
  const ASSET_SPIRAL = "/assets/spiral.png";
  const ASSET_ELEPHANT = "data:image/png;base64,";

  function esc(s) {
    return (s || '').toString().replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  }

  function fmtDateID(isoStr) {
    if (!isoStr) return '';
    const d = new Date(isoStr + 'T00:00:00');
    if (isNaN(d)) return '';
    return `${d.getDate()} ${IDN_MONTHS[d.getMonth()]} ${d.getFullYear()}`;
  }
  function addMonths(isoStr, n) {
    if (!isoStr) return '';
    const d = new Date(isoStr + 'T00:00:00');
    if (isNaN(d)) return '';
    d.setMonth(d.getMonth() + n);
    return `${d.getDate()} ${IDN_MONTHS[d.getMonth()]} ${d.getFullYear()}`;
  }

  function bulletList(text) {
    const lines = (text || '').split('\n').map(l => l.trim()).filter(Boolean);
    if (!lines.length) return '<p style="color:#b7c1c4;font-style:italic;">Belum diisi.</p>';
    let html = '<ul>';
    lines.forEach(line => {
      if (/^\d+[\.\)]/.test(line)) {
        html += `<li class="sub">${esc(line)}</li>`;
      } else {
        const clean = line.replace(/^[-•]\s*/, '');
        html += `<li class="main">${esc(clean)}</li>`;
      }
    });
    html += '</ul>';
    return html;
  }
  function paragraph(text) {
    if (!text || !text.trim()) return '<p style="color:#b7c1c4;font-style:italic;">Belum diisi.</p>';
    return `<p>${esc(text).replace(/\n/g, '<br>')}</p>`;
  }

  function iconPin() { return `<svg class="icon" viewBox="0 0 24 24"><path d="M12 21s7-6.3 7-12a7 7 0 1 0-14 0c0 5.7 7 12 7 12z"/><circle cx="12" cy="9" r="2.4"/></svg>`; }
  function iconGlobe() { return `<svg class="icon" viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M3 12h18M12 3c2.7 2.7 4 6 4 9s-1.3 6.3-4 9c-2.7-2.7-4-6-4-9s1.3-6.3 4-9z"/></svg>`; }
  function iconCal() { return `<svg class="icon" viewBox="0 0 24 24"><rect x="3" y="5" width="18" height="16" rx="2"/><path d="M3 10h18M8 3v4M16 3v4"/></svg>`; }
  function iconHand() { return `<svg class="icon" viewBox="0 0 24 24"><path d="M2 12l4-3 4 2 4-3 4 2 4-3"/><path d="M8 14l3 3 2-2M14 14l3 3"/></svg>`; }
  function iconDoc() { return `<svg class="icon" viewBox="0 0 24 24"><path d="M6 3h8l5 5v13a1 1 0 0 1-1 1H6a1 1 0 0 1-1-1V4a1 1 0 0 1 1-1z"/><path d="M14 3v5h5"/></svg>`; }

  /* ---------------- empty state factory ---------------- */
  function emptyDim() {
    return { temuan: '', kekuatan: '', kelemahan: '', dimata: '', catatan: '' };
  }
  function buildEmptyState() {
    return {
      cover: {
        nama: '', umur: '', paspor: '', negara: '', visa: '',
        tujuan: '', sponsor: '', tanggal: '', fotoDataUrl: null
      },
      skor_kuantitatif: {
        pekerjaan: 0, skala_usaha: 0, jabatan: 0, lama_bekerja: 0, penghasilan: 0, bukti_dokumen: 0
      },
      penilaian_kualitatif: {
        kemampuan_cuti: '-', konsistensi_dokumen: '', catatan_lokasi: '', tier_katalog: '-'
      },
      kesimpulan: {
        value: 'RED FLAG', risiko: 'RED FLAG', total_skor: 0, narasi_penilaian: '', rekomendasi: ''
      }
    };
  }

  /* ---------------- page templates ---------------- */
  function coverPageHTML(state) {
    const c = state.cover || {};
    const nama = c.nama || '(isi nama disini)';
    const umur = c.umur || '—';
    const paspor = c.paspor || '(isi nomor disini)';
    const negara = c.negara || 'isi disini';
    const visa = c.visa || 'isi disini';
    const tujuan = c.tujuan || 'isi disini';
    const sponsor = c.sponsor || 'isi disini';
    const tglIso = c.tanggal || '';
    const tglDisplay = tglIso ? fmtDateID(tglIso) : 'dd mmmm yyyy';
    const masaDisplay = tglIso ? addMonths(tglIso, 3) : 'dd mmmm yyyy';

    const avatarInner = c.fotoDataUrl
      ? `<img src="${c.fotoDataUrl}">`
      : `<svg class="icon" viewBox="0 0 24 24" style="width:55%;height:55%;color:#fff;stroke-width:2"><circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.5-7 8-7s8 3 8 7"/></svg>`;

    return `
  <div class="page cover" id="pageCover">
    <div class="page-inner">
      <img class="spiral" src="${ASSET_SPIRAL}">
      <img class="logo" src="${ASSET_LOGO}">
      <div class="eyebrow">LAPORAN PENILAIAN PROFIL</div>
      <div class="title">PROFILE<br>ASSESSMENT<span class="accent">REPORT</span></div>
      <div class="sub">Penilaian sistematis atas kekuatan profil visa Anda</div>

      <div class="info-card">
        <div class="passport-tag">NOMOR PASSPOR<br><b>${esc(paspor)}</b></div>
        <div class="id-row">
          <div class="avatar">${avatarInner}</div>
          <div class="id-meta">
            <div class="name">${esc(nama)}</div>
            <div class="age">Umur&nbsp; ${esc(umur)}</div>
          </div>
        </div>
        <div class="info-grid">
          <div class="info-item"><div class="lbl">${iconPin()}Negara Tujuan</div><div class="val">${esc(negara)}</div></div>
          <div class="info-item"><div class="lbl">${iconGlobe()}Jenis Visa</div><div class="val">${esc(visa)}</div></div>
          <div class="info-item"><div class="lbl">${iconCal()}Tujuan Perjalanan</div><div class="val">${esc(tujuan)}</div></div>
          <div class="info-item"><div class="lbl">${iconHand()}Sponsor</div><div class="val">${esc(sponsor)}</div></div>
        </div>
      </div>

      <div class="date-row">
        <div class="date-box">
          <label>Tanggal penilaian :</label>
          <div class="date-field">${tglDisplay}</div>
        </div>
        <div class="date-box">
          <div class="date-field"><span class="lbl2">Masa Berlaku Report :</span>${masaDisplay}</div>
          <div class="masa-note">*Masa berlaku dihitung dari tanggal penilaian, dan berlaku selama 3 Bulan</div>
        </div>
      </div>

      <img class="elephant" src="${ASSET_ELEPHANT}">
      <div class="footer-note">Disusun oleh Sistem Penilaian Profil WEPOSE — instrumen terstruktur berbasis pengalaman senior planner. Laporan ini menilai kesiapan, bukan jaminan hasil.</div>
    </div>
  </div>`;
  }

  function getStatusLabelAndClass(val) {
    if (val === 'RF' || val === 'rf') {
      return { label: 'RED FLAG', displayVal: 'RF', className: 'status-kritis', pct: 10 };
    }
    const num = typeof val === 'number' ? val : parseInt(val, 10);
    if (isNaN(num)) {
      return { label: 'NEUTRAL', displayVal: '0', className: 'status-perhatian', pct: 50 };
    }
    if (num >= 5) return { label: 'STRONG', displayVal: '+5', className: 'status-kuat', pct: 100 };
    if (num >= 3) return { label: 'MEDIUM', displayVal: '+3', className: 'status-cukup', pct: 75 };
    if (num >= 0) return { label: 'NEUTRAL', displayVal: '0', className: 'status-perhatian', pct: 50 };
    return { label: 'WEAK', displayVal: '-3', className: 'status-kritis', pct: 25 };
  }

  function renderPillarRow(label, scoreVal, catatanVal) {
    const { label: statusLabel, displayVal, className, pct } = getStatusLabelAndClass(scoreVal);
    const hasNote = catatanVal && catatanVal.trim() !== '';

    return `
      <div class="pillar-report-item" style="margin-bottom: 2.5mm; padding-bottom: 2mm; border-bottom: 1px dashed #e7ecec;">
        <div class="status-bar-row">
          <div class="status-bar-lbl" style="width: 46mm;">${esc(label)}</div>
          <div class="status-bar-track">
            <div class="status-bar-fill ${className}" style="width: ${pct}%"></div>
          </div>
          <div class="status-bar-val" style="width: 10mm;">${displayVal}</div>
          <div class="status-bar-badge-wrap">
            <span class="status-badge ${className}">${statusLabel}</span>
          </div>
        </div>
        ${hasNote ? `<div style="font-size: 7.8pt; color: #527582; margin-top: 1.2mm; padding-left: 1mm; font-style: italic; line-height: 1.35;"><b>Catatan:</b> ${esc(catatanVal)}</div>` : ''}
      </div>
    `;
  }

  function getKualitatifBadgeClass(val) {
    if (val === 'STRONG') return 'badge-rendah';
    if (val === 'RED FLAG') return 'badge-tinggi';
    return 'badge-sedang';
  }

  function skorKuantitatifPageHTML(state, pageNum, totalPages) {
    const paspor = (state.cover && state.cover.paspor) || '(isi nomor disini)';
    const sq = state.skor_kuantitatif || {};
    
    const pekerjaan = sq.pekerjaan !== undefined ? sq.pekerjaan : 0;
    const skala_usaha = sq.skala_usaha !== undefined ? sq.skala_usaha : 0;
    const jabatan = sq.jabatan !== undefined ? sq.jabatan : 0;
    const lama_bekerja = sq.lama_bekerja !== undefined ? sq.lama_bekerja : 0;
    const penghasilan = sq.penghasilan !== undefined ? sq.penghasilan : 0;
    const bukti_dokumen = sq.bukti_dokumen !== undefined ? sq.bukti_dokumen : 0;
    
    const k = state.kesimpulan || {};
    let totalDisplay = k.total_skor !== undefined ? String(k.total_skor) : '0';
    let isRF = totalDisplay.includes('RF') || pekerjaan === 'RF' || skala_usaha === 'RF' || jabatan === 'RF' || lama_bekerja === 'RF' || penghasilan === 'RF' || bukti_dokumen === 'RF';

    let totalStatusLabel = 'CUKUP';
    let totalClassName = 'status-cukup';
    const numTotal = parseInt(totalDisplay, 10) || 0;

    if (isRF || numTotal <= 0) {
      totalStatusLabel = 'KRITIS';
      totalClassName = 'status-kritis';
    } else if (numTotal >= 22) {
      totalStatusLabel = 'KUAT';
      totalClassName = 'status-kuat';
    } else if (numTotal >= 10) {
      totalStatusLabel = 'CUKUP';
      totalClassName = 'status-cukup';
    } else if (numTotal >= 1) {
      totalStatusLabel = 'PERLU PERHATIAN';
      totalClassName = 'status-perhatian';
    }

    return `
  <div class="page dim" id="pageSkorKuantitatif">
    <div class="page-inner">
      <div class="page-head">
        <div class="eyebrow-sm">PROFILE ASSESSMENT REPORT</div>
        <div class="passport-chip">${iconDoc()}<div>NOMOR PASSPOR<br><b>${esc(paspor)}</b></div></div>
      </div>
      <div class="section-title-row">
        <div class="roman-pill">I</div>
        <h2>1. Skor Kuantitatif</h2>
      </div>

      <div class="box box-temuan" style="margin-bottom: 5mm; padding: 5mm 6.5mm;">
        <h3 style="margin-bottom: 3.5mm;">Rincian Nilai &amp; Catatan 6 Pilar Assessment</h3>
        <div class="status-bars-container">
          ${renderPillarRow('Kekuatan Pekerjaan', pekerjaan, sq.pekerjaan_catatan)}
          ${renderPillarRow('Skala Usaha', skala_usaha, sq.skala_usaha_catatan)}
          ${renderPillarRow('Tingkat Jabatan', jabatan, sq.jabatan_catatan)}
          ${renderPillarRow('Lama Bekerja', lama_bekerja, sq.lama_bekerja_catatan)}
          ${renderPillarRow('Penghasilan / Finansial', penghasilan, sq.penghasilan_catatan)}
          ${renderPillarRow('Bukti Dokumen Pendukung', bukti_dokumen, sq.bukti_dokumen_catatan)}
        </div>
      </div>

      <div class="stat-row">
        <div class="stat-card" style="display:flex; align-items:center; justify-content:space-between; padding: 4.5mm 6.5mm;">
          <div>
            <div class="lbl" style="margin-bottom:1mm;">Total Skor Kuantitatif</div>
            <div class="val" style="font-size:22pt; line-height:1.1;">${totalDisplay} <span style="font-size:11pt; color:#7c8c92; font-weight:normal;">/ 30</span></div>
          </div>
          <div>
            <div class="lbl" style="text-align:right; margin-bottom:2mm;">Tingkat Kesiapan</div>
            <span class="status-badge ${totalClassName}" style="padding:2mm 5mm; font-size:10.5pt; font-weight:800; border-radius:20mm; display:inline-block;">${totalStatusLabel}</span>
          </div>
        </div>
      </div>

    </div>
    <div class="page-footer"><span>WEPOSE</span><span>Pages ${pageNum} of ${totalPages}</span></div>
  </div>`;
  }

  function penilaianKualitatifPageHTML(state, pageNum, totalPages) {
    const paspor = (state.cover && state.cover.paspor) || '(isi nomor disini)';
    const pk = state.penilaian_kualitatif || {};
    const kemampuanCuti = pk.kemampuan_cuti || '-';
    const tierKatalog = pk.tier_katalog || '-';

    return `
  <div class="page dim" id="pagePenilaianKualitatif">
    <div class="page-inner">
      <div class="page-head">
        <div class="eyebrow-sm">PROFILE ASSESSMENT REPORT</div>
        <div class="passport-chip">${iconDoc()}<div>NOMOR PASSPOR<br><b>${esc(paspor)}</b></div></div>
      </div>
      <div class="section-title-row">
        <div class="roman-pill">II</div>
        <h2>2. Penilaian Kualitatif &amp; Kategori</h2>
      </div>

      <div class="stat-row" style="margin-bottom: 5mm;">
        <div class="stat-card" style="display:flex; align-items:center; justify-content:space-between; padding: 4.5mm 6mm;">
          <div>
            <div class="lbl" style="margin-bottom:1.5mm;">Kemampuan Cuti</div>
            <span class="badge ${getKualitatifBadgeClass(kemampuanCuti)}">${esc(kemampuanCuti)}</span>
          </div>
          <div style="text-align:right;">
            <div class="lbl" style="margin-bottom:1.5mm;">Tier Katalog</div>
            <span class="badge badge-sedang" style="background:#eef1f2; color:var(--navy); font-weight:800;">${esc(tierKatalog)}</span>
          </div>
        </div>
      </div>

      <div class="box box-temuan" style="margin-bottom: 4mm;">
        <h3>KONSISTENSI DOKUMEN</h3>
        ${paragraph(pk.konsistensi_dokumen)}
      </div>

      <div class="box box-dimata" style="margin-bottom: 4mm;">
        <h3>CATATAN LOKASI</h3>
        ${paragraph(pk.catatan_lokasi)}
      </div>

    </div>
    <div class="page-footer"><span>WEPOSE</span><span>Pages ${pageNum} of ${totalPages}</span></div>
  </div>`;
  }

  function kesimpulanPageHTML(state, pageNum, totalPages) {
    const k = state.kesimpulan || {};
    const paspor = (state.cover && state.cover.paspor) || '(isi nomor disini)';
    const kesimpulanVal = k.value || k.risiko || 'WEAK';

    return `
  <div class="page dim" id="pageKesimpulan">
    <div class="page-inner">
      <div class="page-head">
        <div class="eyebrow-sm">PROFILE ASSESSMENT REPORT</div>
        <div class="passport-chip">${iconDoc()}<div>NOMOR PASSPOR<br><b>${esc(paspor)}</b></div></div>
      </div>
      <div class="section-title-row">
        <div class="roman-pill">✓</div>
        <h2>3. Analisis, Kesimpulan &amp; Rekomendasi</h2>
      </div>

      <div class="stat-row" style="margin-bottom: 5mm;">
        <div class="stat-card" style="padding: 4mm 6mm; display:flex; align-items:center; justify-content:space-between;">
          <div class="lbl" style="margin:0;">Kesimpulan Profil</div>
          <span class="badge ${getKualitatifBadgeClass(kesimpulanVal)}" style="font-size:10.5pt; padding:2mm 6mm;">${esc(kesimpulanVal)}</span>
        </div>
      </div>

      <div class="box box-temuan" style="margin-bottom: 4mm;">
        <h3>NARASI PENILAIAN</h3>
        ${paragraph(k.narasi_penilaian)}
      </div>
      <div class="box box-kekuatan" style="margin-bottom: 4mm;">
        <h3>REKOMENDASI TINDAKAN</h3>
        ${bulletList(k.rekomendasi)}
      </div>

    </div>
    <div class="page-footer"><span>WEPOSE</span><span>Pages ${pageNum} of ${totalPages}</span></div>
  </div>`;
  }

  function renderAllPagesHTML(state) {
    const total = 4;
    let html = '';
    html += coverPageHTML(state);
    html += skorKuantitatifPageHTML(state, 2, total);
    html += penilaianKualitatifPageHTML(state, 3, total);
    html += kesimpulanPageHTML(state, 4, total);
    return html;
  }

  /* Auto-fit: kalau isian sebuah dimensi kepanjangan untuk muat di 1
     halaman A4, ini dijalankan bertahap supaya tetap TERBACA selama
     mungkin, dan tetap DIJAMIN 1 halaman utuh (tidak pernah kepotong):

     1) Tier fit-1 -> fit-2 -> fit-3: font-size & padding box dikecilkan
        sedikit demi sedikit (lihat report.css). Ini yang dicoba duluan
        karena hasilnya jauh lebih enak dibaca daripada scale kasar.
     2) Kalau setelah tier-3 MASIH kepanjangan (isian ekstrem panjang),
        baru seluruh .page-inner di-scale turun sampai benar-benar pas.
        Sengaja TANPA batas minimum scale, supaya tidak pernah ada
        konten yang kepotong/melebihi ukuran A4 — walau kalau sampai
        titik ini teksnya memang akan terlihat kecil sekali (tandanya
        isiannya perlu dipersingkat manual). */
  function autofitAll(root) {
    const scope = root || document;
    scope.querySelectorAll('.page').forEach(page => {
      const inner = page.querySelector('.page-inner');
      if (!inner) return;

      inner.classList.remove('fit-1', 'fit-2', 'fit-3');
      inner.style.transform = 'none';
      inner.style.width = '';

      const pageHeight = page.clientHeight;
      if (!(pageHeight > 0)) return;

      const tiers = ['fit-1', 'fit-2', 'fit-3'];
      for (const tier of tiers) {
        if (inner.scrollHeight <= pageHeight) break;
        inner.classList.add(tier);
      }

      const naturalHeight = inner.scrollHeight;
      if (naturalHeight > pageHeight) {
        const scale = pageHeight / naturalHeight;
        inner.style.width = (100 / scale) + '%';
        inner.style.transform = 'scale(' + scale + ')';
      }
    });
  }

  /* Tunggu semua <img> di dalam root selesai load/decode. Penting
     supaya Puppeteer tidak generate PDF sebelum foto/logo/gajah
     ter-render sempurna. */
  function waitForImages(root) {
    const scope = root || document;
    const imgs = Array.from(scope.querySelectorAll('img'));
    return Promise.all(imgs.map(img => {
      if (img.complete) return Promise.resolve();
      return new Promise(resolve => {
        img.addEventListener('load', resolve, { once: true });
        img.addEventListener('error', resolve, { once: true });
      });
    }));
  }

  global.WeposeReport = {
    IDN_MONTHS, ROMAN, DIM_NAMES,
    esc, fmtDateID, addMonths, bulletList, paragraph,
    buildEmptyState, emptyDim,
    coverPageHTML, skorKuantitatifPageHTML, penilaianKualitatifPageHTML, kesimpulanPageHTML,
    renderAllPagesHTML, autofitAll, waitForImages
  };
})(typeof window !== 'undefined' ? window : globalThis);
